queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?air_traffic_controller a :Air_traffic_controller .
    ?air_traffic_controller p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?ground_staff a :Ground_staff .
    ?ground_staff p:name ?name .
    ?ground_staff p:Salary ?salary_f .
    FILTER(STR(?salary_f) = "60000 per year")
    BIND(?name AS ?o0)
  }
}

